/**
 * Sync Trace
 *
 * Entrypoint: node starter/index.js
 */

const readline = require("readline");

const SNIPPETS = {
  basic: "A C",
  nested: "1 4",
  chain: "start middle end",
};

async function main() {
  const rl = readline.createInterface({ input: process.stdin });
  for await (const line of rl) {
    const id = line.trim();
    const order = SNIPPETS[id];
    if (!order) {
      process.stdout.write("ERROR: unknown snippet\n");
    } else {
      process.stdout.write("Sync order: " + order + "\n");
    }
    break;
  }
  rl.close();
}

main();

/**
 * Output Order Predictor
 *
 * Entrypoint: node starter/index.js
 */

const SNIPPETS = [
  {
    name: "basic",
    order: "A B micro timer",
    classifications: [
      "A:sync",
      "B:sync",
      "micro:microtask",
      "timer:task",
    ],
    explanation:
      "Sync logs run on the call stack first. Promise reactions are microtasks and drain before the setTimeout task runs.",
  },
  {
    name: "async-await",
    order: "A C B",
    classifications: ["A:sync", "C:sync", "B:microtask"],
    explanation:
      "main() runs until await, which schedules the rest as a microtask. C prints before B resumes.",
  },
  {
    name: "chained-microtasks",
    order: "m1 m2 t1",
    classifications: ["m1:microtask", "m2:microtask", "t1:task"],
    explanation:
      "Microtasks m1 and m2 drain completely before task t1 from setTimeout.",
  },
  {
    name: "trick",
    order: "start end micro timer",
    classifications: [
      "start:sync",
      "end:sync",
      "micro:microtask",
      "timer:task",
    ],
    explanation:
      "Microtasks always run before the next task, so micro prints before timer even with setTimeout(0).",
  },
];

function formatSnippet(snippet) {
  const lines = [
    `=== ${snippet.name} ===`,
    `order: ${snippet.order}`,
    ...snippet.classifications.map((c) => `  ${c}`),
    `explanation: ${snippet.explanation}`,
  ];
  return lines.join("\n");
}

function main() {
  for (const snippet of SNIPPETS) {
    process.stdout.write(formatSnippet(snippet) + "\n\n");
  }
}

main();

/**
 * Microtask Before Timer
 *
 * Entrypoint: node starter/index.js
 */

function main() {
  process.stdout.write("order: start end micro timer\n");
  process.stdout.write("rule: microtasks drain before the next task\n");
  process.stdout.write("micro_before_timer: true\n");
}

main();

/**
 * Promise Chain Builder
 *
 * Entrypoint: node starter/index.js
 */

const readline = require("readline");

function fakeRead(path, callback) {
  setTimeout(() => {
    if (path === "fail") {
      callback(new Error("not found"));
      return;
    }
    callback(null, "data:" + path);
  }, 0);
}

function readAsPromise(path) {
  return new Promise((resolve, reject) => {
    fakeRead(path, (err, data) => {
      if (err) reject(err);
      else resolve(data);
    });
  });
}

function runPipeline(path) {
  return readAsPromise(path)
    .then((data) => data + " -> parsed")
    .then((data) => data + " -> done")
    .catch((err) => "ERROR: " + err.message);
}

async function main() {
  const rl = readline.createInterface({ input: process.stdin });
  for await (const line of rl) {
    const path = line.trim();
    const result = await runPipeline(path);
    process.stdout.write(result + "\n");
    break;
  }
  rl.close();
}

main();

/**
 * Sequential Async Runner
 *
 * Entrypoint: node starter/index.js
 */

const readline = require("readline");

function delay(ms, label) {
  return new Promise((resolve) => {
    setTimeout(() => resolve(label), ms);
  });
}

async function stepFetch() {
  return delay(10, "fetch:ok");
}

async function stepTransform() {
  return delay(10, "transform:ok");
}

async function stepSave(shouldFail) {
  if (shouldFail) {
    throw new Error("save failed");
  }
  return delay(10, "save:ok");
}

async function runPipeline(shouldFail) {
  try {
    const a = await stepFetch();
    const b = await stepTransform();
    const c = await stepSave(shouldFail);
    return [a, b, c].join(" | ");
  } catch (err) {
    return "ERROR: " + err.message;
  }
}

async function main() {
  const rl = readline.createInterface({ input: process.stdin });
  for await (const line of rl) {
    const mode = line.trim();
    const shouldFail = mode === "fail";
    const result = await runPipeline(shouldFail);
    process.stdout.write(result + "\n");
    break;
  }
  rl.close();
}

main();

/**
 * To Result
 *
 * Entrypoint: node starter/index.js
 */

const readline = require("readline");

async function toResult(promise) {
  try {
    const value = await promise;
    return { ok: true, value };
  } catch (error) {
    return { ok: false, error };
  }
}

async function main() {
  const rl = readline.createInterface({ input: process.stdin });
  for await (const line of rl) {
    const mode = line.trim();
    if (mode === "ok") {
      const result = await toResult(Promise.resolve(42));
      process.stdout.write("ok:" + result.value + "\n");
    } else if (mode === "fail") {
      const result = await toResult(Promise.reject(new Error("boom")));
      process.stdout.write("err:" + result.error.message + "\n");
    } else {
      process.stdout.write("ERROR: use ok or fail\n");
    }
    break;
  }
  rl.close();
}

main();

